   float a : 8;    // C2150
   int i : 8;      // OK
};
```

# Compiler Error C2158

> 'type' : #pragma make_public directive is currently supported for native non-template types only

## Remarks

The [make_public](../../preprocessor/make-public.md) pragma can only be applied to a native, non-template type.

## Example

The following example generates C2158.

```cpp
// C2158.cpp
// compile with: /clr /c
ref class A {};
#pragma make_public(A)   // C2158

template< typename T >
class B {};
#pragma make_public(B)   // C2158
#pragma make_public(B<int>)   // C2158

void C () {}
#pragma make_public(C)   // C2158

class D {};
#pragma make_public(D)   // OK
```

# Compiler Error C2164

> 'function' : intrinsic function not declared

## Remarks

An `intrinsic` pragma uses an undeclared function (only occurs with **/Oi**). Or, one of the compiler intrinsics was used without including its header file.

## Example

The following example generates C2164:

```c
// C2164.c
// compile with: /c
// processor: x86
// Uncomment the following line to resolve.
// #include "xmmintrin.h"
void b(float *p) {
   _mm_load_ss(p);   // C2164
}
```

# Compiler Error C2171

> 'operator' : illegal on operands of type 'type'

## Remarks

A unary operator is used with an invalid operand type.

## Examples

The following example generates C2171.

```cpp
// C2171.cpp
int main() {
   double d, d1;
   d = ~d1;   // C2171

   // OK
   int d2 = 0, d3 = 0;
   d2 = ~d3;
}
```

The following example generates C2171.

```cpp
// C2171_b.cpp
// compile with: /c
class A {
public:
   A() { STF( &A::D ); }

   void D() {}
   void DTF() {
      (*TF)();   // C2171
      (this->*TF)();   // OK
   }

   void STF(void (A::*fnc)()) {
      TF = fnc;
   }

private:
   void (A::*TF)();
};
```

# Compiler Error C2178

> '*identifier*' cannot be declared with '*specifier*' specifier

## Remarks

A **`mutable`** specifier was used in a declaration, but the specifier is not allowed in this context. It can only be applied to non-static, non-const, and non-reference data members. For more information, see [Mutable Data Members](../../cpp/mutable-data-members-cpp.md).

A **`consteval`** specifier was used on a [destructor](../../cpp/destructors-cpp.md), allocation function, or deallocation function.

## Example: `mutable`

The following example shows how C2178 may occur with the **`mutable`** specifier, and how to resolve it:

```cpp
// C2178_mutable.cpp
// compile with: /c

struct S
{
    mutable const int i;   // C2178, remove mutable or const to resolve
};

mutable int x = 4;   // C2178, remove mutable to resolve
```

## Example: `consteval`

The following example shows how C2178 may occur with the **`consteval`** specifier. To resolve this error, remove all **`consteval`** specifiers:

```cpp
// C2178_consteval.cpp
// compile with: /c /std:c++20

#include <cstddef>

struct S
{
    consteval ~S() {}   // C2178

    consteval static void* operator new(std::size_t size);   // C2178
    consteval static void operator delete(void* ptr);        // C2178
};
```

# Compiler Error C2179

> 'type' : an attribute argument cannot use type parameters

## Remarks

A generic type parameter is resolved at runtime. However, an attribute parameter must be resolved at compile time. Therefore, you cannot use a generic type parameter as an argument to an attribute.

## Example

The following example generates C2179.

```cpp
// C2179.cpp
// compile with: /clr
using namespace System;

public ref struct Attr : Attribute {
   Attr(Type ^ a) {
      x = a;
   }

   Type ^ x;
};

ref struct G {};

generic<typename T>
public ref class Z {
public:
   Type ^ d;
   [Attr(T::typeid)]   // C2179
   // try the following line instead
   // [Attr(G::typeid)]
   T t;
};
```

# Compiler Error C2180

> controlling expression has type 'type'

## Remarks

The controlling expression in an **`if`**, **`while`**, **`for`**, or **`do`** statement is an expression cast to **`void`**. To fix this issue, change the controlling expression to one that produces a **`bool`** or a type that can be converted to **`bool`**.

## Example

The following example generates C2180:

```c
// C2180.c

int main() {
   while ((void)1)   // C2180
      return 1;
   while (1)         // OK
      return 0;
}
```

# Compiler Error C2181

> illegal else without matching if

## Remarks

Each **`else`** must have a matching **`if`**.

## Example

The following example generates C2181:

```cpp
// C2181.cpp
int main() {
   int i = 0;
   else   // C2181
      i = 1;
}
```

Possible resolution:

```cpp
// C2181b.cpp
int main() {
   int i = 0;
   if(i)
      i = 0;
   else
      i = 1;
}
```

# Compiler Error C2184

> 'type' : illegal type for __except expression, must be an integral

## Remarks

A type was used in an [__except](../../c-language/try-except-statement-c.md) statement, but the type is not allowed.

## Example

The following example generates C2184:

```cpp
// C2184.cpp
void f() {
   int * p;
   __try{}
   __except(p){};   // C2184
}
```

Possible resolution:

```cpp
// C2184b.cpp
// compile with: /c
void f() {
   int i = 0;
   __try{}
   __except(i){};
}
```

