};

struct Derived : Base {};

int main()
{
    Derived derived;
    Base* pointer_to_base = &derived;

    dynamic_cast<Derived*>(pointer_to_base);   // C4541

    typeid(*pointer_to_base);   // C4541
    typeid(pointer_to_base);    // OK
}
```

